import React, { useState, useEffect } from 'react';
import { useQuery, useMutation } from '@apollo/client';
import { GET_RISKS, CREATE_RISK, UPDATE_RISK } from '../graphql/queries';
import { Risk, Customer, Tag } from '../types';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

interface Props {
  editingTicket?: Risk | null;
  onEditTicket?: (risk: Risk) => void;
}

const Risks: React.FC<Props> = ({ editingTicket, onEditTicket }) => {
