    title: string;
    customers: string;
    tags: string;
    priority: string;
    status: string;
    riskId?: string; // Add riskId to formData for edit mode
  }>({
    title: '',
    customers: '',
    tags: '',
    priority: 'Media',
    status: 'Pendiente',
  });
